Here's how to test `DataFetcher` with MSTest, covering success, failure, cancellation, and timeouts:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello world")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.NotFound));
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com/missing"));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange — handler that delays so cancellation can fire
        using var cts = new CancellationTokenSource();
        var handler = new FakeHandler(delay: TimeSpan.FromSeconds(10));
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act — cancel immediately
        cts.Cancel();

        // Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(3000)] // test fails if it takes longer than 3s
    public async Task FetchAsync_WithTimeout_CompletesWithinLimit()
    {
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("fast response")
        });
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Pass TestContext.CancellationToken — gets cancelled when [Timeout] fires
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("fast response", result);
    }

    [TestMethod]
    [Timeout(1000)]
    public async Task FetchAsync_SlowResponse_TimeoutCancelsOperation()
    {
        // Arrange — handler that never completes quickly
        var handler = new FakeHandler(delay: TimeSpan.FromSeconds(30));
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Assert — the [Timeout] fires, CancellationToken cancels the call
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    // --- Fake handler to avoid real HTTP calls ---
    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly HttpResponseMessage? _response;
        private readonly TimeSpan _delay;

        public FakeHandler(HttpResponseMessage response)
        {
            _response = response;
            _delay = TimeSpan.Zero;
        }

        public FakeHandler(TimeSpan delay)
        {
            _delay = delay;
        }

        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (_delay > TimeSpan.Zero)
            {
                await Task.Delay(_delay, cancellationToken); // throws if cancelled
            }

            return _response ?? new HttpResponseMessage(HttpStatusCode.OK);
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---------|-----|
| Mock HttpClient | Custom `HttpMessageHandler` — no mocking library needed |
| Test cancellation | Create a pre-cancelled `CancellationTokenSource`, assert `TaskCanceledException` |
| Test timeouts | `[Timeout(ms)]` + pass `_testContext.CancellationToken` into the method under test |
| Cooperative timeout | MSTest cancels `TestContext.CancellationToken` when `[Timeout]` fires — your async code observes it naturally |
| Exception assertions | `Assert.ThrowsExactlyAsync<T>` instead of `[ExpectedException]` |

The critical insight: **always forward `TestContext.CancellationToken`** to async methods under test. This makes `[Timeout]` actually interrupt the operation rather than just failing after it eventually completes.
